const Store = {
  state: { schemaVersion: 2, activeCameraId: 'default', cameras: [], polygonsByCamera: { default: [] }, imagesMeta: {}, draft: { points: [], type: 'motion_mask', objectType: 'person' } },
  _subs: [],
  subscribe(fn) { this._subs.push(fn); },
  _notify() { this._subs.forEach(fn => fn(this.state)); },
  addPoint(xNorm, yNorm) { this.state.draft.points.push({ x: xNorm, y: yNorm }); this._notify(); },
  closePolygon(name, objectType) {
    if (this.state.draft.points.length < 3) return { ok: false, error: 'min_points' };
    const polys = this.state.polygonsByCamera[this.state.activeCameraId];
    polys.push({ id: 'p_' + crypto.randomUUID(), name, type: this.state.draft.type, objectType, points: this.state.draft.points, closed: true });
    this.state.draft.points = [];
    this._notify();
    return { ok: true };
  }
};

const Platform = {
  readImageFile(file) { return new Promise(res => { const r = new FileReader(); r.onload = e => res(e.target.result); r.readAsDataURL(file); }); },
  async copyText(text) { try { await navigator.clipboard.writeText(text); } catch { const ta = Object.assign(document.createElement('textarea'), { value: text }); document.body.append(ta); ta.select(); document.execCommand('copy'); ta.remove(); } },
  downloadFile(name, text) { const a = document.createElement('a'); a.href = URL.createObjectURL(new Blob([text], { type: 'text/yaml' })); a.download = name; a.click(); }
};
